import{_ as e,o as n,c as a,ag as r}from"./chunks/framework.DGzMGr_a.js";const p=JSON.parse('{"title":"学习路径总览","description":"","frontmatter":{},"headers":[],"relativePath":"guide/index.md","filePath":"guide/index.md","lastUpdated":null}'),s={name:"guide/index.md"};function d(l,t,o,i,g,c){return n(),a("div",null,[...t[0]||(t[0]=[r(`<h1 id="学习路径总览" tabindex="-1">学习路径总览 <a class="header-anchor" href="#学习路径总览" aria-label="Permalink to &quot;学习路径总览&quot;">​</a></h1><p>本页面汇总了从零基础入门到进阶提升的完整学习路径。你可以根据自己的当前水平选择适合的路线。</p><hr><h2 id="🟢-初学者路径" tabindex="-1">🟢 初学者路径 <a class="header-anchor" href="#🟢-初学者路径" aria-label="Permalink to &quot;🟢 初学者路径&quot;">​</a></h2><p>适合零基础或刚接触质量工程的学习者，共 <strong>4 步</strong>，预计总耗时 <strong>8-12 周</strong>。</p><table tabindex="0"><thead><tr><th style="text-align:center;">步骤</th><th>内容</th><th style="text-align:center;">预计时间</th></tr></thead><tbody><tr><td style="text-align:center;"><strong>第一步</strong></td><td>质量工程概述、QC 七大手法基础、常用质量术语</td><td style="text-align:center;">2 周</td></tr><tr><td style="text-align:center;"><strong>第二步</strong></td><td>统计学基础（均值、标准差、正态分布）、SPC 入门</td><td style="text-align:center;">3 周</td></tr><tr><td style="text-align:center;"><strong>第三步</strong></td><td>FMEA 失效模式分析、MSA 测量系统分析基础</td><td style="text-align:center;">3 周</td></tr><tr><td style="text-align:center;"><strong>第四步</strong></td><td>ISO 9001 质量管理体系、PPAP 与 8D 报告入门</td><td style="text-align:center;">3 周</td></tr></tbody></table><blockquote><p><strong>建议</strong>：按顺序学习，每完成一步后通过练习巩固。完成此路径后你将对质量工程有全面基础认知。</p></blockquote><hr><h2 id="🔵-进阶者路径" tabindex="-1">🔵 进阶者路径 <a class="header-anchor" href="#🔵-进阶者路径" aria-label="Permalink to &quot;🔵 进阶者路径&quot;">​</a></h2><p>适合已具备基础质量知识、希望深化技能的学员，共 <strong>3 步</strong>，预计总耗时 <strong>6-9 周</strong>。</p><table tabindex="0"><thead><tr><th style="text-align:center;">步骤</th><th>内容</th><th style="text-align:center;">预计时间</th></tr></thead><tbody><tr><td style="text-align:center;"><strong>第一步</strong></td><td>六西格玛方法论（DMAIC）、统计分析深入（假设检验、回归分析）</td><td style="text-align:center;">3 周</td></tr><tr><td style="text-align:center;"><strong>第二步</strong></td><td>IATF 16949 标准详解、过程审核（VDA 6.3）</td><td style="text-align:center;">3 周</td></tr><tr><td style="text-align:center;"><strong>第三步</strong></td><td>CQE 认证备考 / 六西格玛绿带/黑带备考</td><td style="text-align:center;">3 周</td></tr></tbody></table><blockquote><p><strong>建议</strong>：如果你已熟悉 QC 七大手法和 SPC 基础，直接从进阶路径开始会效率更高。</p></blockquote><hr><h2 id="📚-推荐学习顺序" tabindex="-1">📚 推荐学习顺序 <a class="header-anchor" href="#📚-推荐学习顺序" aria-label="Permalink to &quot;📚 推荐学习顺序&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>初学者 ──▶ 基础入门 ──▶ 质量工具 ──▶ 体系标准 ──▶ 质检实操 ──▶ 认证考试</span></span>
<span class="line"><span>                          │</span></span>
<span class="line"><span>                          └── 进阶者（跳至六西格玛与 IATF 16949）</span></span></code></pre></div><ul><li>前往 <strong><a href="/guide/getting-started">快速入门</a></strong> 了解学习前的准备工作</li><li>前往 <strong><a href="/guide/prerequisites">预备知识</a></strong> 复习必备的统计和质量管理概念</li></ul>`,16)])])}const x=e(s,[["render",d]]);export{p as __pageData,x as default};
